  ('disabled-7fec267e-moex-00091', 'disabled-7fec267e', 'disabled-7fec267e-moex-114-3082b5f1', 'sub-disabled-7fec267e-05', NULL, 'single_choice', '甲市政府自行興建公立停車場，委託乙公司經營。由於乙未能對於該停車 場內手扶梯定期進行保養，因而造成人民跌落受傷，在此等情形下甲之責 任為何？', '["由於實際經營管理者為乙，故甲無國家賠償法之適用", "雖然該停車場為甲所興建，然該等事故並非設置有所欠缺所造成，故無 國家賠償法之適用", "雖然該停車場委託私人管理，然因該停車場仍供公共使用，故甲仍應依 法負國家賠償責任", "該事故雖沒有成立國家賠償責任之可能，但甲仍須對該受傷人民負民事 侵權行為損害賠償責任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:43+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": "a7faea101c05", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "一般行政"}'::jsonb, NULL),
  ('disabled-7fec267e-moex-00092', 'disabled-7fec267e', 'disabled-7fec267e-moex-114-3082b5f1', 'sub-disabled-7fec267e-05', NULL, 'single_choice', '甲為A國人民，來我國騎自行車環島，行經道路路燈旁休息時，因路燈漏 電電擊休克致死，甲之父母請求我國國家賠償，下列敘述何者正確？', '["外國人並無國家賠償法之適用", "道路路燈屬自然公物內之設施，如經適當之警告或標示，而人民仍從事 具危險性活動，得減輕或免除國家賠償責任", "被害人甲死亡，其父母依國家賠償法適用民法第194條，得請求賠償慰 撫金", "須視我國與A國有無締結對等互惠之行政協議，以決定是否賠償"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:43+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": "a7faea101c05", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "一般行政"}'::jsonb, NULL),
